class ApiService {
  static const String baseUrl = 'http://localhost:8000';

  Future<Map<String, dynamic>> getSimulationData(Map<String, dynamic> params) async {
    try {
      final response = await http.post(
        Uri.parse('$baseUrl/api/simulation'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode(params),
      );
      return jsonDecode(response.body);
    } catch (e) {
      return {'error': e.toString()};
    }
  }

  Future<List<double>> calculateTrajectory({
    required double angle,
    required double velocity,
    required double gravity,
  }) async {
    final result = await getSimulationData({
      'angle': angle,
      'velocity': velocity,
      'gravity': gravity,
    });
    return List<double>.from(result['trajectory'] ?? []);
  }
}

import 'package:flutter_tts/flutter_tts.dart';

class SpeechService {
  final FlutterTts _flutterTts = FlutterTts();

  SpeechService() {
    _flutterTts.setLanguage('en-US');
    _flutterTts.setSpeechRate(0.5);
    _flutterTts.setVolume(1.0);
    _flutterTts.setPitch(1.0);
  }

  Future<void> speak(String text) async {
    await _flutterTts.speak(text);
  }

  Future<void> stop() async {
    await _flutterTts.stop();
  }

  void dispose() {
    _flutterTts.stop();
  }
}

import 'package:flutter/foundation.dart';

class SimulationModel extends ChangeNotifier {
  double _angle = 45.0;
  double _velocity = 20.0;
  double _gravity = 9.8;

  double get angle => _angle;
  double get velocity => _velocity;
  double get gravity => _gravity;

  void setAngle(double value) {
    _angle = value;
    notifyListeners();
  }

  void setVelocity(double value) {
    _velocity = value;
    notifyListeners();
  }

  void setGravity(double value) {
    _gravity = value;
    notifyListeners();
  }

  double get maxRange {
    final angleRad = _angle * 3.14159 / 180;
    return (_velocity * _velocity * (2 * _angle.abs() > 180 ? -1 : 1) * 
            (2 * _angle.abs() > 180 ? 0 : 1)) /
        _gravity;
  }

  double get maxHeight {
    final angleRad = _angle * 3.14159 / 180;
    return (_velocity * _velocity * 
            (angleRad.abs() * angleRad.abs())) /
        (2 * _gravity);
  }
}
